Panel.BackgroundTransparency = 1
Panel.Position = UDim2.new(0.5,0,0.5,36)
TwE(Panel, 0.32, Enum.EasingStyle.Back, Enum.EasingDirection.Out,
    {BackgroundTransparency=0, Position=UDim2.new(0.5,0,0.5,0)})
Tw(Backdrop, 0.22, {BackgroundTransparency=0.35})

-- ════════════════════════════════════════════════════════
-- CLOSE FUNCTION
-- ════════════════════════════════════════════════════════
local function CloseUI()
    getgenv().UI_CLOSED = true
    local b = Lighting:FindFirstChild("ZXCHUB_KeyBlur")
    Tw(Panel, 0.18, {BackgroundTransparency=1, Position=UDim2.new(0.5,0,0.5,28)})
    Tw(Backdrop, 0.18, {BackgroundTransparency=1})
    task.wait(0.20)
    if b then b:Destroy() end
    if GUI and GUI.Parent then GUI:Destroy() end
end

CloseBtn.MouseButton1Click:Connect(CloseUI)

-- ════════════════════════════════════════════════════════
-- GET KEY BUTTON
-- ════════════════════════════════════════════════════════
GKBtn.MouseButton1Click:Connect(function()
    local link = "https://zxchub.online/getkey"
    if setclipboard then
        setclipboard(link)
        SetStatus("Link copied! Paste it into your browser.", C.grn, 5)
        gkLbl.Text = "Copied!"
        task.delay(2.5, function() gkLbl.Text = "Get Key" end)
    else
        SetStatus("Get your key at: zxchub.online/getkey", C.txt, 6)
    end
end)

-- ════════════════════════════════════════════════════════
-- VERIFY KEY
-- ════════════════════════════════════════════════════════
local verifying = false

local function DoVerify(rawKey)
    if verifying then return end
    local key = rawKey:gsub("%s+","")
    if key == "" then
        SetStatus("Please enter a key first.", C.acc, 3)
        task.spawn(ShakeInput); return
    end

    verifying = true
    vkLbl.Text = "Checking..."; VKBtn.Active = false

    local result = Junkie.check_key(key)

    if result and result.valid then
        fsSave(key)
        ShowLoading(false)
        ShowSuccess(result.message == "KEYLESS" and "Keyless Mode!" or "Key Verified!")
        getgenv().SCRIPT_KEY = key
        verifying = false
        CloseUI()
    else
        SetStatus("Invalid key. Try again or get a new one.", C.acc, 5)
        task.spawn(ShakeInput)
        Tw(InputWrap, 0.09, {BackgroundColor3=Color3.fromRGB(50,16,16)})
        task.delay(0.38, function()
            Tw(InputWrap, 0.18, {BackgroundColor3=C.bg2})
        end)
        Tw(inputStroke, 0.12, {Color=C.acc, Thickness=1.5, Transparency=0})
        task.delay(1.2, function()
            Tw(inputStroke, 0.18, {Color=C.brd2, Thickness=1, Transparency=0.25})
        end)
        vkLbl.Text = "Verify Key"; VKBtn.Active = true
        verifying = false
    end
end

VKBtn.MouseButton1Click:Connect(function() DoVerify(KeyInput.Text) end)
KeyInput.FocusLost:Connect(function(enter)
    if enter then DoVerify(KeyInput.Text) end
end)

-- ════════════════════════════════════════════════════════
-- STARTUP — auto-check saved key / keyless
-- ════════════════════════════════════════════════════════
task.spawn(function()
    ShowLoading(true, "Checking verification")

    local savedKey = fsLoad() or getgenv().SCRIPT_KEY
    local result   = Junkie.check_key(savedKey)

    if result and result.valid then
        if result.message == "KEYLESS" then
            ShowLoading(false)
            ShowSuccess("Keyless Mode!")
            getgenv().SCRIPT_KEY = "KEYLESS"
            CloseUI(); return
        end
        if result.message == "KEY_VALID" then
            ShowLoading(false)
            ShowSuccess(savedKey and "Saved Key Verified!" or "Key Verified!")
            getgenv().SCRIPT_KEY = savedKey
            CloseUI(); return
        end
        if savedKey then fsClear() end
    end

    ShowLoading(false)
end)

-- ════════════════════════════════════════════════════════
-- WAIT UNTIL UI CLOSES
-- (key is available in getgenv().SCRIPT_KEY afterwards)
-- ════════════════════════════════════════════════════════
while not getgenv().UI_CLOSED do
    task.wait(0.1)
end

